/**
 * ESM Loader — Lightweight entry point for Omniguide AI SDK.
 *
 * ~3-5 KB gzipped. No React, no omniguide-core/react/bigcommerce at load time.
 * Features load on demand via dynamic import() — Vite code-splits automatically.
 *
 * Usage:
 *   <script type="module" src="omniguide-sdk.esm.js"></script>
 *   <script nomodule src="omniguide-sdk.standalone.js"></script>
 *   <link rel="stylesheet" href="omniguide-tokens.css">
 *   <script>
 *     Omniguide.init({ websiteId: 'https://mystore.com/' });
 *   </script>
 */

import { setupSearchTrigger, type SearchTriggerResult } from './search-trigger.js';
import { loadCss, prefetchCss, prefetchJs, ensureReact } from './load-utils.js';
import type { BundleInitConfig, OmniguideInstance } from './types.js';
import type { SearchIntegration, FeatureIntegration, MountTarget } from '@swiftotter/omniguide-core';
import {
  initPreviewFromQueryParam,
  setPreviewApiUrl,
  clearPreviewApiUrl,
  isPreviewMode,
} from '@swiftotter/omniguide-core';

// Check query param override before any init() call
initPreviewFromQueryParam();

declare const __OMNIGUIDE_VERSION__: string;

// ── Asset URL resolution ─────────────────────────────────────────

/**
 * Resolve the base URL for loading sibling CSS assets.
 * Uses import.meta.url to determine where the loader was loaded from.
 */
function resolveBase(): string {
  try {
    const url = new URL(import.meta.url);
    return url.href.substring(0, url.href.lastIndexOf('/') + 1);
  } catch {
    return './';
  }
}

// ── Dynamic import factories (Vite code-splits these) ────────────

// These static dynamic imports let Vite analyze the dependency graph
// and create proper code-split chunks for each feature.
const loadSearchModule = () => import('./features/search.js');
const loadProductFitModule = () => import('./features/product-fit.js');
const loadCategoryGuideModule = () => import('./features/category-guide.js');

// ── CSS asset names (predictable, no hashes) ─────────────────────

const CSS_ASSETS = {
  tokens: 'omniguide-tokens.css',
  search: 'omniguide-search.css',
  productFit: 'omniguide-product-fit.css',
  categoryGuide: 'omniguide-category-guide.css',
} as const;

// ── State ────────────────────────────────────────────────────────

let currentConfig: BundleInitConfig | null = null;
let searchIntegration: SearchIntegration | null = null;
// eslint-disable-next-line @typescript-eslint/no-explicit-any
let searchChunkPromise: Promise<any> | null = null;
let triggerResult: SearchTriggerResult | null = null;
let productFitIntegration: FeatureIntegration | null = null;
let categoryGuideIntegration: FeatureIntegration | null = null;

// ── Micro-spinner ────────────────────────────────────────────────

const SPINNER_ID = 'omniguide-loading-spinner';

function showSearchSpinner(): void {
  if (document.getElementById(SPINNER_ID)) return;
  const overlay = document.createElement('div');
  overlay.id = SPINNER_ID;
  overlay.style.cssText = `
    position:fixed;top:0;left:0;right:0;bottom:0;
    z-index:10001;
    display:flex;align-items:center;justify-content:center;
    background:rgba(0,0,0,0.3);
  `;
  overlay.innerHTML = `
    <div style="
      width:40px;height:40px;
      border:3px solid rgba(255,255,255,0.3);
      border-top-color:#fff;
      border-radius:50%;
      animation:omniguide-spin 0.8s linear infinite;
    "></div>
    <style>@keyframes omniguide-spin{to{transform:rotate(360deg)}}</style>
  `;
  document.body.appendChild(overlay);
}

function hideSearchSpinner(): void {
  document.getElementById(SPINNER_ID)?.remove();
}

// ── Visibility observer ──────────────────────────────────────────

function observeVisibility(el: Element, rootMargin: string, onVisible: () => void): IntersectionObserver {
  const io = new IntersectionObserver(
    (entries) => {
      for (const entry of entries) {
        if (entry.isIntersecting) {
          io.disconnect();
          onVisible();
          return;
        }
      }
    },
    { rootMargin },
  );
  io.observe(el);
  return io;
}

// ── Search lazy loading ──────────────────────────────────────────

function getSearchChunk() {
  if (!searchChunkPromise) {
    searchChunkPromise = loadSearchModule();
  }
  return searchChunkPromise;
}

async function handleOpenSearch(query: string, source: string, base: string): Promise<void> {
  if (searchIntegration) {
    searchIntegration.openSearch(query, source);
    return;
  }

  // Show micro-spinner if loading takes >150ms
  const spinnerTimeout = window.setTimeout(() => showSearchSpinner(), 150);

  try {
    const [mod] = await Promise.all([
      getSearchChunk(),
      loadCss(base + CSS_ASSETS.search),
      ensureReact(),
    ]);

    clearTimeout(spinnerTimeout);
    hideSearchSpinner();

    const omniguideConfig = mod.buildConfig(currentConfig);
    const platformAdapter = mod.buildPlatformAdapter(currentConfig);
    searchIntegration = new mod.BCSearchIntegration({
      config: omniguideConfig,
      platformAdapter,
      skipDomSetup: true,
    });
    searchIntegration.init();
    searchIntegration.openSearch(query, source);

    // Invoke search.onOpen callback if provided
    currentConfig?.search?.onOpen?.(source);
  } catch (e) {
    clearTimeout(spinnerTimeout);
    hideSearchSpinner();
    console.error('[Omniguide] Failed to load search:', e);
  }
}

// ── PDP/PLP lazy mounting ────────────────────────────────────────

async function mountProductFit(config: BundleInitConfig, base: string): Promise<void> {
  try {
    const [mod] = await Promise.all([
      loadProductFitModule(),
      loadCss(base + CSS_ASSETS.productFit),
      ensureReact(),
    ]);
    const omniguideConfig = mod.buildConfig(config);
    const platformAdapter = mod.buildPlatformAdapter(config);
    productFitIntegration = new mod.BCProductFitIntegration({
      config: omniguideConfig,
      platformAdapter,
      mount: config.pdpWidget?.mount,
    });
    productFitIntegration.init();
  } catch (e) {
    console.error('[Omniguide] Failed to load product fit:', e);
  }
}

async function mountCategoryGuide(config: BundleInitConfig, base: string): Promise<void> {
  try {
    const [mod] = await Promise.all([
      loadCategoryGuideModule(),
      loadCss(base + CSS_ASSETS.categoryGuide),
      ensureReact(),
    ]);
    const omniguideConfig = mod.buildConfig(config);
    const platformAdapter = mod.buildPlatformAdapter(config);
    categoryGuideIntegration = new mod.BCCategoryGuideIntegration({
      config: omniguideConfig,
      platformAdapter,
      mount: config.plpWidget?.mount,
    });
    categoryGuideIntegration.init();
  } catch (e) {
    console.error('[Omniguide] Failed to load category guide:', e);
  }
}

// ── CSS token injection ──────────────────────────────────────────

function injectTokenOverrides(tokens: Record<string, string>): void {
  const style = document.createElement('style');
  style.id = 'omniguide-token-overrides';
  const props = Object.entries(tokens)
    .map(([key, value]) => {
      const prop = key.startsWith('--') ? key : `--${key}`;
      return `  ${prop}: ${value};`;
    })
    .join('\n');
  style.textContent = `:root {\n${props}\n}`;
  document.head.appendChild(style);
}

// ── Observation target resolution ─────────────────────────────────

/**
 * Determine which element to observe for IntersectionObserver visibility-loading.
 * When a `mount` config is provided, the observation target is the mount target itself
 * (since the actual container doesn't exist yet — it's created at mount time).
 */
function resolveObserveTarget(
  mount: MountTarget | undefined,
  selector: string | undefined,
  defaultSelector: string,
): Element | null {
  if (mount) {
    return mount.target instanceof HTMLElement
      ? mount.target
      : document.querySelector(mount.target);
  }
  return document.querySelector(selector ?? defaultSelector);
}

// ── Main init ────────────────────────────────────────────────────

export function init(config: BundleInitConfig): OmniguideInstance {
  if (!config.websiteId) {
    throw new Error('[Omniguide] websiteId is required in config');
  }

  currentConfig = config;
  const base = resolveBase();
  const features = { search: true, productFit: true, categoryGuide: true, ...config.features };

  // Inject custom token overrides if provided
  if (config.tokens) {
    injectTokenOverrides(config.tokens);
  }

  // 1. Load tokens CSS immediately (tiny, ~3 KB)
  loadCss(base + CSS_ASSETS.tokens);

  // 2. Search trigger setup (sync DOM, no React)
  if (features.search && config.search?.replace !== null) {
    triggerResult = setupSearchTrigger(
      {
        replace: config.search?.replace,
        renderTrigger: config.search?.renderTrigger,
        icon: config.search?.icon,
        selectors: config.selectors,
        websiteId: config.websiteId,
        ui: config.ui,
      },
      (query, source) => handleOpenSearch(query, source, base),
    );

    // Intent-based prefetch
    const loadMode = config.search?.loadMode ?? 'intent';
    if (loadMode === 'intent' && triggerResult) {
      triggerResult.addIntentListeners(() => {
        // Prefetch search JS chunk (triggers modulepreload)
        getSearchChunk();
        // Prefetch search CSS
        prefetchCss(base + CSS_ASSETS.search);
      });
    } else if (loadMode === 'idle') {
      const schedule = window.requestIdleCallback ?? ((cb: IdleRequestCallback) => window.setTimeout(cb, 2000));
      schedule(() => {
        getSearchChunk();
        prefetchCss(base + CSS_ASSETS.search);
      });
    }
    // 'click' = no prefetch, load on demand
  }

  // Track IntersectionObservers for cleanup
  const observers: IntersectionObserver[] = [];

  // 3. PDP widget — IntersectionObserver
  if (features.productFit) {
    const pdpObserveEl = resolveObserveTarget(config.pdpWidget?.mount, config.pdpWidget?.selector, '[data-omniguide-pdp], #product-recommendations-root');
    if (pdpObserveEl) {
      const loadMode = config.pdpWidget?.loadMode ?? 'visible';
      if (loadMode === 'immediate') {
        mountProductFit(config, base);
      } else {
        const io = observeVisibility(pdpObserveEl, config.pdpWidget?.rootMargin ?? '600px', () => {
          mountProductFit(config, base);
        });
        observers.push(io);
      }
    }
  }

  // 4. PLP widget — IntersectionObserver
  if (features.categoryGuide) {
    const plpObserveEl = resolveObserveTarget(config.plpWidget?.mount, config.plpWidget?.selector, '[data-omniguide-plp], #category-recommendations-root');
    if (plpObserveEl) {
      const loadMode = config.plpWidget?.loadMode ?? 'visible';
      if (loadMode === 'immediate') {
        mountCategoryGuide(config, base);
      } else {
        const io = observeVisibility(plpObserveEl, config.plpWidget?.rootMargin ?? '600px', () => {
          mountCategoryGuide(config, base);
        });
        observers.push(io);
      }
    }
  }

  const instance: OmniguideInstance = {
    search: null, // Set lazily when search chunk loads
    productFit: null,
    categoryGuide: null,
    openSearch: (query?: string) => handleOpenSearch(query ?? '', 'api', base),
    destroy() {
      triggerResult?.destroy();
      searchIntegration?.destroy();
      productFitIntegration?.destroy();
      categoryGuideIntegration?.destroy();
      for (const io of observers) io.disconnect();
      document.getElementById('omniguide-token-overrides')?.remove();

      // Reset state
      searchIntegration = null;
      searchChunkPromise = null;
      productFitIntegration = null;
      categoryGuideIntegration = null;
      triggerResult = null;
      currentConfig = null;
    },
  };

  return instance;
}

/**
 * Get the bundle version.
 */
export function getVersion(): string {
  return typeof __OMNIGUIDE_VERSION__ !== 'undefined' ? __OMNIGUIDE_VERSION__ : 'unknown';
}

// ── Global exposure ──────────────────────────────────────────────

// ── Preview mode console API ─────────────────────────────────────────

function setPreviewApi(url: string): void {
  setPreviewApiUrl(url);
  console.info(`[Omniguide] Preview API set to ${url}. Reload the page for changes to take effect.`);
}

function clearPreviewApi(): void {
  clearPreviewApiUrl();
  console.info('[Omniguide] Preview API cleared. Reload the page to use the default API.');
}

// ── Global exposure ──────────────────────────────────────────────

if (typeof window !== 'undefined') {
  (window as Record<string, unknown>)['Omniguide'] = {
    init,
    getVersion,
    setPreviewApi,
    clearPreviewApi,
    isPreviewMode,
  };
}

// ── Declarative auto-init ────────────────────────────────────────

function declarativeInit(): void {
  const scripts = document.querySelectorAll('script[data-omniguide-config]');
  scripts.forEach((script) => {
    const raw = script.getAttribute('data-omniguide-config');
    if (!raw) return;
    try {
      const config = JSON.parse(raw) as BundleInitConfig;
      init(config);
    } catch (e) {
      console.error('[Omniguide] Failed to parse data-omniguide-config:', e);
    }
  });
}

if (typeof document !== 'undefined') {
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', declarativeInit);
  } else {
    declarativeInit();
  }
}
