/**
 * Search trigger — Pure DOM module for setting up search icon/button.
 *
 * Zero React imports. Zero omniguide-core/react/bigcommerce imports.
 * Only `import type` for erased type references.
 *
 * Extracted from BCSearchIntegration.swapSearchIcon() + overrideSearchBehavior()
 * and BCMobileSearchIntegration.
 */

// ── Types ──────────────────────────────────────────────────────────

export interface SearchTriggerConfig {
  /** What element to replace with the trigger */
  replace?: { selector: string; strategy?: 'replace' | 'append' | 'before' | 'after' } | null;

  /**
   * Custom trigger renderer. Receives { mount, open, close }.
   * Return cleanup function (optional).
   */
  renderTrigger?: (ctx: {
    mount: Element;
    open: (query?: string) => void;
    close: () => void;
  }) => (() => void) | void;

  /** Custom icon SVG string (used by default trigger renderer) */
  icon?: string;

  /** DOM selectors for search integration */
  selectors?: {
    rootContainer?: string;
    searchExpandButton?: string;
    searchToggles?: string;
    searchInputs?: string;
    searchForms?: string;
    quickSearchResults?: string;
    mobileMenu?: string;
    mobileNav?: string;
    wordpress?: {
      searchButton?: string;
      searchForms?: string;
      searchInputs?: string;
    };
  };

  /** Website ID for multi-instance filtering */
  websiteId: string;

  /** UI config for mobile */
  ui?: {
    mobile?: {
      breakpoint?: number;
      searchWidth?: string;
    };
  };
}

export interface SearchTriggerResult {
  /** Open the search modal */
  openSearch: (query?: string, source?: string) => void;
  /** Attach intent listeners (hover/focus) to trigger element. Returns cleanup. */
  addIntentListeners: (onIntent: () => void) => () => void;
  /** Tear down all DOM changes and event listeners */
  destroy: () => void;
}

