// ── Override desktop search ──────────────────────────────────────

function isWordPressEnvironment(selectors: SearchTriggerConfig['selectors']): boolean {
  const wpSearchButton = selectors?.wordpress?.searchButton ?? '.header-search-btn';
  return (
    window.location.pathname.includes('/blog') ||
    document.querySelector(wpSearchButton) !== null ||
    document.body.classList.contains('blog')
  );
}

function overrideWordPressSearch(
  selectors: SearchTriggerConfig['selectors'],
  openSearch: (query: string, source: string) => void,
  listeners: TrackedListener[],
): void {
  const wp = selectors?.wordpress ?? {};
  const wpSearchButton = wp.searchButton ?? '.header-search-btn';
  const wpSearchForms = wp.searchForms ?? '.header-search form, form.search-form';
  const wpSearchInputs = wp.searchInputs ?? '.header-search input[type="search"], .search-field';

  document.querySelectorAll(wpSearchButton).forEach((button) => {
    addTrackedListener(listeners, button, 'click', ((e: Event) => {
      e.preventDefault();
      e.stopImmediatePropagation();
      openSearch('', 'wordpress_search_button');
    }) as EventListener, true);
  });

  document.querySelectorAll(wpSearchForms).forEach((form) => {
    addTrackedListener(listeners, form, 'submit', ((e: Event) => {
      e.preventDefault();
      e.stopImmediatePropagation();
      const input = form.querySelector('input[type="search"], .search-field') as HTMLInputElement | null;
      const query = input?.value ?? '';
      openSearch(query, 'wordpress_search_form_submit');
      if (input) input.value = '';
    }) as EventListener, true);
  });

  document.querySelectorAll(wpSearchInputs).forEach((input) => {
    addTrackedListener(listeners, input, 'focus', ((e: Event) => {
      e.preventDefault();
      e.stopImmediatePropagation();
      (e.target as HTMLElement)?.blur();
      openSearch('', 'wordpress_search_input_focus');
    }) as EventListener, true);
  });
}

function overrideDesktopSearch(
  selectors: SearchTriggerConfig['selectors'],
  openSearch: (query: string, source: string) => void,
  listeners: TrackedListener[],
): void {
  const searchToggles = selectors?.searchToggles ?? '.navUser-action--quickSearch, [aria-label="Search toggle"]';
  const searchInputs = selectors?.searchInputs ?? 'input[name="search_query"]';
  const searchForms = selectors?.searchForms ?? 'form[action="/search.php"], form[data-search="quickSearch"]';
  const mobileMenu = selectors?.mobileMenu ?? '#mobileMenu, .mobileMenu-search';

  document.querySelectorAll(searchToggles).forEach((toggle) => {
    addTrackedListener(listeners, toggle, 'click', ((e: Event) => {
      e.preventDefault();
      e.stopImmediatePropagation();
      openSearch('', 'nav_search_button');
    }) as EventListener, true);
  });

  const isInMobileMenu = (el: Element) => {
    const menuSelectors = mobileMenu.split(',').map((s) => s.trim());
    return menuSelectors.some((selector) => el.closest(selector));
  };

  document.querySelectorAll(searchInputs).forEach((input) => {
    if (isInMobileMenu(input)) return;
    addTrackedListener(listeners, input, 'focus', ((e: Event) => {
      e.preventDefault();
      e.stopImmediatePropagation();
      (e.target as HTMLElement)?.blur();
      openSearch('', 'search_input_focus');
    }) as EventListener, true);
  });

  document.querySelectorAll(searchForms).forEach((form) => {
    if (isInMobileMenu(form)) return;
    addTrackedListener(listeners, form, 'submit', ((e: Event) => {
      e.preventDefault();
      e.stopImmediatePropagation();
      const firstInputSelector = (searchInputs.split(',')[0] ?? searchInputs).trim();
      const input = form.querySelector(firstInputSelector) as HTMLInputElement | null;
      const query = input?.value ?? '';
      openSearch(query, 'search_form_submit');
      if (input) input.value = '';
    }) as EventListener, true);
  });
}

// ── Mobile search bar replacement ────────────────────────────────

interface MobileSearchCleanup {
  destroy: () => void;
}

function setupMobileSearch(
  config: SearchTriggerConfig,
  openSearch: (query: string, source: string) => void,
): MobileSearchCleanup {
  const replacementId = 'ai-mobile-search-replacement';
  const styleId = 'ai-mobile-search-styles';
  const breakpoint = config.ui?.mobile?.breakpoint ?? 767;
  const searchWidth = config.ui?.mobile?.searchWidth ?? '80%';

  // Inject responsive styles
  if (!document.getElementById(styleId)) {
    const style = document.createElement('style');
    style.id = styleId;
    style.textContent = `
      @media (max-width: ${breakpoint}px) {
        .navPages-quickSearch form,
        .navPages-quickSearch input,
        .navPages-quickSearch button[type="submit"] {
          display: none !important;
        }
        #${replacementId} {
          display: flex !important;
        }
        body.ai-search-active {
          position: fixed;
          width: 100%;
          top: 0;
          left: 0;
          right: 0;
          bottom: 0;
          overflow: hidden;
        }
      }
      @media (min-width: ${breakpoint + 1}px) {
        #${replacementId} {
          display: none !important;
        }
      }
    `;
    document.head.appendChild(style);
  }

  // Create replacement button
  function createSearchReplacement(): HTMLElement {
    const container = document.createElement('div');
    container.id = replacementId;
    container.setAttribute('role', 'button');
    container.setAttribute('aria-label', 'Open conversational search');
    container.setAttribute('tabindex', '0');

    Object.assign(container.style, {
      display: 'flex',
      alignItems: 'center',
      gap: '8px',
      padding: '8px 16px',
      backgroundColor: '#f5f5f5',
      border: '1px solid #ddd',
      borderRadius: '8px',
      cursor: 'pointer',
      width: searchWidth,
      transition: 'all 0.2s ease',
    });

    const iconSvg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    iconSvg.setAttribute('viewBox', '0 0 24 24');
    iconSvg.setAttribute('fill', 'none');
    iconSvg.setAttribute('stroke', 'currentColor');
    iconSvg.setAttribute('stroke-width', '2');
    iconSvg.setAttribute('stroke-linecap', 'round');
    iconSvg.setAttribute('stroke-linejoin', 'round');
    Object.assign(iconSvg.style, { width: '20px', height: '20px', flexShrink: '0', color: '#666' });

    const circle = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
    circle.setAttribute('cx', '11');
    circle.setAttribute('cy', '11');
    circle.setAttribute('r', '8');

    const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
    path.setAttribute('d', 'm21 21-4.35-4.35');

    iconSvg.appendChild(circle);
    iconSvg.appendChild(path);

    const text = document.createElement('span');
    Object.assign(text.style, {
      fontSize: '14px',
      color: '#333',
      whiteSpace: 'nowrap',
      overflow: 'hidden',
      textOverflow: 'ellipsis',
    });
    text.textContent = 'Conversational Search';

    container.appendChild(iconSvg);
    container.appendChild(text);

    container.addEventListener('mouseenter', () => {
      container.style.backgroundColor = '#e8e8e8';
      container.style.borderColor = '#ccc';
    });
    container.addEventListener('mouseleave', () => {
      container.style.backgroundColor = '#f5f5f5';
      container.style.borderColor = '#ddd';
    });
    container.addEventListener('click', (e) => {
      e.preventDefault();
      e.stopPropagation();
      openSearch('', 'mobile_menu_search');
    });
    container.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        openSearch('', 'mobile_menu_search_keyboard');
      }
    });

    return container;
  }

  // Replace search bar in mobile nav
  function replaceSearchBar(): boolean {
    if (document.getElementById(replacementId)) return true;
    const searchContainer = document.querySelector('.navPages-quickSearch');
    if (!searchContainer) return false;

    const replacement = createSearchReplacement();
    searchContainer.innerHTML = '';
    searchContainer.appendChild(replacement);

    requestAnimationFrame(() => {
      replacement.style.width = 'auto';
      requestAnimationFrame(() => {
        replacement.style.width = searchWidth;
      });
    });
    return true;
  }

  if (!replaceSearchBar()) {
    setTimeout(replaceSearchBar, 100);
  }

  // MutationObserver for AJAX navigation
  const observer = new MutationObserver(() => {
    const searchContainer = document.querySelector('.navPages-quickSearch');
    if (searchContainer && !document.getElementById(replacementId)) {
      replaceSearchBar();
    }
  });
  observer.observe(document.body, { childList: true, subtree: true });

  return {
    destroy() {
      document.getElementById(replacementId)?.remove();
      document.getElementById(styleId)?.remove();
      observer.disconnect();
    },
  };
}

// ── Main orchestrator ────────────────────────────────────────────

export function setupSearchTrigger(
  config: SearchTriggerConfig,
  onOpenSearch: (query: string, source: string) => void,
): SearchTriggerResult | null {
  const listeners: TrackedListener[] = [];
  const rootId = config.selectors?.rootContainer ?? 'ai-search-root';
  let triggerElement: Element | null = null;
  let customCleanup: (() => void) | void | null = null;
  let mobileCleanup: MobileSearchCleanup | null = null;

  // Close helper — dispatches event + removes body class
  const closeSearch = (): void => {
    if (document.body.getAttribute('data-omniguide-search') === config.websiteId) {
      document.body.classList.remove('ai-search-active');
      document.body.removeAttribute('data-omniguide-search');
    }
    window.dispatchEvent(new CustomEvent('closeAISearch', {
      detail: { websiteId: config.websiteId },
    }));
  };

  // Open helper — adds body class + dispatches event
  const openSearch = (query = '', source = 'unknown'): void => {
    document.body.classList.add('ai-search-active');
    document.body.setAttribute('data-omniguide-search', config.websiteId);
    onOpenSearch(query, source);
  };

  // Inject base styles (hide default search, z-index, body scroll lock)
  injectSearchStyles(config.selectors, rootId);

  // Custom renderTrigger takes precedence
  if (config.renderTrigger && config.replace?.selector) {
    const mount = document.querySelector(config.replace.selector);
    if (mount) {
      triggerElement = mount;
      customCleanup = config.renderTrigger({
        mount,
        open: (query?: string) => openSearch(query ?? '', 'custom_trigger'),
        close: closeSearch,
      });
    }
  } else if (config.replace?.selector) {
    // Use replace strategy with default icon
    const mount = document.querySelector(config.replace.selector);
    if (mount) {
      triggerElement = mount;
      const strategy = config.replace.strategy ?? 'replace';
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.setAttribute('aria-label', 'AI Search');
      btn.innerHTML = config.icon ?? DEFAULT_SEARCH_ICON;
      btn.style.cssText = 'cursor:pointer;background:none;border:none;padding:0;display:inline-flex;align-items:center;';

      addTrackedListener(listeners, btn, 'click', () => openSearch('', 'custom_selector_trigger'));

      if (strategy === 'replace') {
        mount.replaceWith(btn);
        triggerElement = btn;
      } else if (strategy === 'append') {
        mount.appendChild(btn);
        triggerElement = btn;
      } else if (strategy === 'before') {
        mount.parentNode?.insertBefore(btn, mount);
        triggerElement = btn;
      } else if (strategy === 'after') {
        mount.parentNode?.insertBefore(btn, mount.nextSibling);
        triggerElement = btn;
      }
    }
  } else {
    // Default: swap icon + override desktop search behavior + mobile replacement
    triggerElement = swapSearchIcon(config.selectors, config.icon);

    const isDesktop = window.innerWidth > 767;
    if (isDesktop) {
      if (isWordPressEnvironment(config.selectors)) {
        overrideWordPressSearch(config.selectors, openSearch, listeners);
      } else {
        overrideDesktopSearch(config.selectors, openSearch, listeners);
      }
    }

    mobileCleanup = setupMobileSearch(config, openSearch);
  }

  // Listen for close events from the search modal
  const handleClose = ((e: CustomEvent) => {
    if (e.detail?.websiteId && e.detail.websiteId !== config.websiteId) return;
    closeSearch();
  }) as EventListener;
  window.addEventListener('closeAISearch', handleClose);

  return {
    openSearch,

    addIntentListeners(onIntent: () => void): () => void {
      let fired = false;
      const intentHandler = () => {
        if (fired) return;
        fired = true;
        onIntent();
      };

      const intentListeners: TrackedListener[] = [];

      // Listen on the trigger element if available
      if (triggerElement) {
        addTrackedListener(intentListeners, triggerElement, 'mouseenter', intentHandler);
        addTrackedListener(intentListeners, triggerElement, 'focusin', intentHandler);
      }

      // Also listen on search toggles (may differ from triggerElement)
      const searchToggles = config.selectors?.searchToggles ?? '.navUser-action--quickSearch, [aria-label="Search toggle"]';
      document.querySelectorAll(searchToggles).forEach((toggle) => {
        addTrackedListener(intentListeners, toggle, 'mouseenter', intentHandler);
        addTrackedListener(intentListeners, toggle, 'focusin', intentHandler);
      });

      // Listen for keyboard shortcut intent (Ctrl/Cmd + K)
      const keyHandler = ((e: KeyboardEvent) => {
        if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
          intentHandler();
        }
      }) as EventListener;
      addTrackedListener(intentListeners, document, 'keydown', keyHandler);

      return () => removeTrackedListeners(intentListeners);
    },

    destroy() {
      removeTrackedListeners(listeners);
      window.removeEventListener('closeAISearch', handleClose);
      if (typeof customCleanup === 'function') customCleanup();
      mobileCleanup?.destroy();
      document.getElementById(TRIGGER_STYLE_ID)?.remove();
    },
  };
}
