/**
 * Load utilities — CSS loading, JS prefetch, React auto-detection.
 *
 * Tiny module (~1 KB) included in the ESM loader chunk.
 * No React, no omniguide-core/react/bigcommerce imports.
 */

// ── CSS loading ──────────────────────────────────────────────────

const loadedCss = new Set<string>();

/**
 * Load a CSS stylesheet. Resolves when loaded, rejects on error.
 * Deduplicates by URL.
 */
export function loadCss(url: string): Promise<void> {
  if (loadedCss.has(url)) return Promise.resolve();
  loadedCss.add(url);
  return new Promise((resolve, reject) => {
    const link = document.createElement('link');
    link.rel = 'stylesheet';
    link.href = url;
    link.onload = () => resolve();
    link.onerror = () => reject(new Error(`[Omniguide] Failed to load CSS: ${url}`));
    document.head.appendChild(link);
  });
}

/**
 * Preload a CSS file (doesn't apply it yet — prefetch only).
 */
export function prefetchCss(url: string): void {
  if (loadedCss.has(url)) return;
  // Check for existing preload link
  if (document.querySelector(`link[rel="preload"][href="${url}"]`)) return;
  const link = document.createElement('link');
  link.rel = 'preload';
  link.as = 'style';
  link.href = url;
  document.head.appendChild(link);
}

// ── JS prefetch ──────────────────────────────────────────────────

const prefetchedJs = new Set<string>();

/**
 * Prefetch a JS module (doesn't execute — prefetch only).
 */
export function prefetchJs(url: string): void {
  if (prefetchedJs.has(url)) return;
  prefetchedJs.add(url);
  const link = document.createElement('link');
  link.rel = 'modulepreload';
  link.href = url;
  document.head.appendChild(link);
}

// ── React auto-detection ─────────────────────────────────────────

declare global {
  interface Window {
    React?: unknown;
    ReactDOM?: unknown;
  }
}

let reactPromise: Promise<void> | null = null;

/**
 * Ensure React is available globally.
 * If window.React exists → noop.
 * If not → dynamically import the bundled vendor/react chunk.
 */
export async function ensureReact(): Promise<void> {
  if (window.React && window.ReactDOM) return;
  if (reactPromise) return reactPromise;

  // vendor-react.js is built separately (vite.config.vendor-react.ts) with React bundled.
  // Use @vite-ignore so the main ESM build doesn't try to include it (React is external there).
  // Resolve URL relative to this module's location.
  const base = new URL('./', import.meta.url).href;
  reactPromise = import(/* @vite-ignore */ base + 'vendor-react.js').then(() => {
    // vendor-react.js sets window.React and window.ReactDOM
  });
  return reactPromise;
}
