/**
 * Preview mode — allows developers to point the SDK at a staging API
 * without affecting other users.
 *
 * Activation:
 *   - Query param: ?omniguide_preview=https://staging.swiftotter.com
 *   - Console API: Omniguide.setPreviewApi('https://staging.swiftotter.com')
 *
 * Deactivation:
 *   - Query param: ?omniguide_preview=off
 *   - Console API: Omniguide.clearPreviewApi()
 *   - Click "Deactivate" on the preview banner
 */

const PREVIEW_KEY = 'omniguide_preview_api';
const PREVIEW_PARAM = 'omniguide_preview';

const ALLOWED_PREVIEW_HOSTS = [
  'staging.swiftotter.com',
  'verdict.swiftotter.com',
  'localhost',
];

function isAllowedHost(hostname: string): boolean {
  return ALLOWED_PREVIEW_HOSTS.some(
    (h) => hostname === h || hostname.endsWith('.' + h),
  );
}

/**
 * Get the preview API URL from localStorage, or null if not set.
 */
export function getPreviewApiUrl(): string | null {
  try {
    return localStorage.getItem(PREVIEW_KEY);
  } catch {
    return null;
  }
}

/**
 * Check if preview mode is currently active.
 */
export function isPreviewMode(): boolean {
  return getPreviewApiUrl() !== null;
}

/**
 * Set a preview API URL. Validates against the allowlist.
 * Throws if the host is not allowed.
 */
export function setPreviewApiUrl(url: string): void {
  const parsed = new URL(url); // throws on invalid URL
  if (!isAllowedHost(parsed.hostname)) {
    throw new Error(
      `[Omniguide] Preview API host "${parsed.hostname}" not in allowlist. ` +
        `Allowed: ${ALLOWED_PREVIEW_HOSTS.join(', ')}`,
    );
  }
  try {
    localStorage.setItem(PREVIEW_KEY, parsed.origin);
  } catch {
    /* localStorage unavailable */
  }
}

/**
 * Clear the preview API URL, returning to the default production API.
 */
export function clearPreviewApiUrl(): void {
  try {
    localStorage.removeItem(PREVIEW_KEY);
  } catch {
    /* localStorage unavailable */
  }
}

/**
 * Read the `?omniguide_preview=` query parameter and persist to localStorage.
 * Call early in bundle entry points, before init() runs.
 *
 * - `?omniguide_preview=https://staging.swiftotter.com` → activates preview
 * - `?omniguide_preview=off` or `?omniguide_preview=clear` → deactivates
 */
export function initPreviewFromQueryParam(): void {
  if (typeof window === 'undefined') return;

  const params = new URLSearchParams(window.location.search);
  const val = params.get(PREVIEW_PARAM);

  if (!val) return;

  if (val === 'off' || val === 'clear') {
    clearPreviewApiUrl();
  } else {
    try {
      setPreviewApiUrl(val);
    } catch {
      /* invalid URL or not in allowlist — ignore silently */
    }
  }
}
